// Solution
function validateImageTag(image) {
  var imageName = image.image_name;
  var imageTag = image.image_tag;
  return imageName && imageName.length > 0 && imageTag && !imageTag.includes(' ');
}

solutions.python:
class Solution:
  def validate_image_tag(self, image):
    image_name = image.image_name
    image_tag = image.image_tag
    return image_name and image_name != '' and not any(char.isspace() for char in image_tag)
